import json

with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            tfm = fw['framework']
            for pkg in fw['topLevelPackages']:
                key = (name, tfm, pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(list(b.keys()) + list(a.keys()))):
    proj, tfm, pkg = key
    bv = b.get(key, '-')
    av = a.get(key, '-')
    if bv != av:
        changes.append((proj, tfm, pkg, bv, av))
    else:
        unchanged.append((proj, tfm, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]}  {c[3]} -> {c[4]}')
else:
    print('None')
print()
print(f'=== UNCHANGED: {len(unchanged)} packages ===')
for u in unchanged[:5]:
    print(f'{u[0]} ({u[1]}): {u[2]}  {u[3]}')
if len(unchanged) > 5:
    print(f'... and {len(unchanged)-5} more')
"

